import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.OsDJF_Ea.js";const d="/docs/modules/audio-slicer.png",g=JSON.parse('{"title":"Audio Slicer","description":"","frontmatter":{},"headers":[],"relativePath":"modules/audio-slicer.md","filePath":"modules/audio-slicer.md"}'),s={name:"modules/audio-slicer.md"};function i(n,t,l,u,c,p){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="audio-slicer" tabindex="-1">Audio Slicer <a class="header-anchor" href="#audio-slicer" aria-label="Permalink to &quot;Audio Slicer&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>Records audio into memory, auto-divides into 2-32 slices, then plays back polyphonically via MIDI. 4-voice with per-slice ADSR and aux send. Uses 3 hardware banks.</p><img src="'+d+'" alt="audio-slicer module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inMono</strong> (audio)</td><td>Mono input (doubles max record time to 40s).</td></tr><tr><td><strong>inL</strong> (audio)</td><td>Left stereo input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right stereo input.</td></tr><tr><td><strong>note</strong></td><td>MIDI note to trigger slices. Each note maps to a slice starting from base note (default C2).</td></tr><tr><td><strong>slice_count</strong></td><td>Number of slices (2-32). Can be modulated for real-time reslicing.</td></tr><tr><td><strong>pitch_cv</strong></td><td>Pitch modulation 0-1 mapped to 0.5x-2x playback speed.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left audio.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right audio.</td></tr><tr><td><strong>auxSendL</strong> (audio)</td><td>Left aux send for effects.</td></tr><tr><td><strong>auxSendR</strong> (audio)</td><td>Right aux send.</td></tr><tr><td><strong>slice</strong></td><td>Current slice number being played.</td></tr><tr><td><strong>slicePosition</strong></td><td>Playback position within current slice 0-1.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Record a drum break, set slice_count to 16, trigger slices from a Sequencer or MIDIIn for breakbeat chopping. Use aux sends to route slices through reverb or delay. Bank 2 controls per-slice ADSR.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(s,[["render",i]]);export{g as __pageData,m as default};
